// startPos が属する行(丁数・行数)を返す。見つからなければ null。
export function lookupLine(fileName, startPos) {
  const entry = sagoromoLineMap[fileName];
  if (!entry) return null;
  const lines = entry.lines;
  let lo = 0, hi = lines.length - 1, ans = -1;
  while (lo <= hi) {
    const mid = (lo + hi) >> 1;
    if (lines[mid].pos <= startPos) { ans = mid; lo = mid + 1; }
    else hi = mid - 1;
  }
  return ans >= 0 ? lines[ans] : null;
}

// 「丁数-行数」文字列 (例 "2オ-1") を返す。
export function lookupPageLine(fileName, startPos) {
  const l = lookupLine(fileName, startPos);
  return l ? `${l.pb}-${l.lb}` : null;
}
